                    heardAboutUs: formData.courseSelection.heardAboutUs,

                    // Additional Info
                    goals: formData.additionalInfo.goals,
                    whyThisProgram: formData.additionalInfo.whyThisProgram,
                    challenges: formData.additionalInfo.challenges,
                    extraInfo: formData.additionalInfo.extraInfo,
                    agreeToTerms: formData.additionalInfo.agreeToTerms
                })
            });

            const data = await response.json();

            if (!response.ok) {
                throw new Error(data.message || 'Failed to submit application');
            }

            // Success case
            setFormStatus({
                submitted: true,
                error: false,
                message: 'Application submitted successfully!',
                loading: false
            });

            // Reset form after 3 seconds
            setTimeout(() => {
                setFormStatus({
                    submitted: false,
                    error: false,
                    message: '',
                    loading: false
                });
                // Reset form data here if needed
                setFormData({
                    personalInfo: {},
                    educationInfo: {},
                    courseSelection: {},
                    additionalInfo: {}
                });
                setActiveStep(0);
            }, 3000);

        } catch (error) {
            console.error('Application submission error:', error);
            setFormStatus({
                submitted: true,
                error: true,
                message: error.message || 'There was an error submitting your application. Please try again.',
                loading: false
            });

            // Clear error message after 3 seconds
            setTimeout(() => {
                setFormStatus({
                    submitted: false,
                    error: false,
                    message: '',
                    loading: false
                });
            }, 3000);
        }
    };


